#include <stdio.h>
#include <stdlib.h>
#define MAX_N 2000
#define MAX_M 1000000

int visited[MAX_N];
int graph[MAX_N][MAX_N];
int N, M;

void dfs(int vertex) {
    visited[vertex] = 1;
    for (int i = 0; i < N; i++) {
        if (graph[vertex][i] == 1 && visited[i] == 0) {
            dfs(i);
        }
    }
}

int count_winning_vertices() {
    int count = 0;
    for (int i = 0; i < N; i++) {
        if (visited[i] == 0) {
            dfs(i);
            count++;
        }
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                graph[i][j] = 0;
            }
        }
        for (int i = 0; i < M; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            graph[x-1][y-1] = 1;
            graph[y-1][x-1] = 1;
        }
        printf("%d\n", count_winning_vertices());
    }
    return 0;
}

