const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MAX_N = 2000;
const MAX_M = 1000000;
let visited = new Array(MAX_N).fill(0);
let graph = new Array(MAX_N).fill(0).map(() => new Array(MAX_N).fill(0));
let N, M;

function dfs(vertex) {
    visited[vertex] = 1;
    for (let i = 0; i < N; i++) {
        if (graph[vertex][i] === 1 && visited[i] === 0) {
            dfs(i);
        }
    }
}

function count_winning_vertices() {
    let count = 0;
    for (let i = 0; i < N; i++) {
        if (visited[i] === 0) {
            dfs(i);
            count++;
        }
    }
    return count;
}

let test_cases = parseInt(lines[idx++]);
while (test_cases-- > 0) {
    [N, M] = lines[idx++].trim().split(' ').map(Number);
    for (let i = 0; i < N; i++) {
        for (let j = 0; j < N; j++) {
            graph[i][j] = 0;
        }
    }
    for (let i = 0; i < M; i++) {
        let [x, y] = lines[idx++].trim().split(' ').map(Number);
        graph[x-1][y-1] = 1;
        graph[y-1][x-1] = 1;
    }
    console.log(count_winning_vertices());
}

